div.p:
thread_pool_enqueue() when queue is full:
c
pthread_mutex_lock(&pool->lock);
if (pool->count >= WORK_QUEUE_CAPACITY) {
pthread_mutex_unlock(&pool->lock);
return -1;          /* ← NON-BLOCKING: never waits */
}

Accept loop on return -1:
c
const char resp_503 =
"HTTP/1.1 503 Service Unavailable\r\n"
"Content-Length: 0\r\n"
"Connection: close\r\n"
"Retry-After: 1\r\n"    / ← backpressure signal /
"\r\n";
send(client_fd, resp_503, strlen(resp_503), MSG_NOSIGNAL);
close(client_fd);           / ← caller retains ownership on -1 */
